import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { showNotification } from '../assets/notifications';
import { useNavigationWithDelay } from '../hooks/useNavigationWithDelay';
import Loading from '../components/Loading';

interface Order {
  _id: string;
  user: {
    email: string;
    firstName: string;
    lastName: string;
  };
  games: Array<{
    game: {
      _id: string;
      title: string;
      platform: string;
      price: number;
    };
    price: number;
  }>;
  totalAmount: number;
  status: string;
  createdAt: string;
}

const Cart: React.FC = () => {
  const { state } = useAuth();
  const { navigateWithDelay, isLoading } = useNavigationWithDelay();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (state.isAuthenticated) {
      fetchOrders();
    }
  }, [state.isAuthenticated]);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      // Read orders from alpha_orders (centralized storage)
      const savedOrders = localStorage.getItem('alpha_orders');
      let orders: Order[] = [];

      if (savedOrders) {
        const parsedOrders = JSON.parse(savedOrders);
        // Filter orders by current user email
        orders = parsedOrders.filter((order: Order) => 
          order.user.email === state.user?.email
        );
      }

      setOrders(orders);
    } catch (error) {
      console.error('Error fetching orders:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!state.isAuthenticated) {
    return (
      <>
        {isLoading && <Loading />}
        <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: '#0a0a0a' }}>
        <div className="card p-8 max-w-md w-full text-center">
          <div className="w-16 h-16 bg-red-600 rounded-xl flex items-center justify-center mx-auto mb-6">
            <span className="text-white font-bold text-2xl">A</span>
          </div>
          <h1 className="text-2xl font-bold text-white mb-4">يرجى تسجيل الدخول</h1>
          <p className="text-gray-400 mb-6">يجب تسجيل الدخول لعرض طلباتك</p>
          <Link to="/login" className="btn-primary inline-block">
            تسجيل الدخول
          </Link>
        </div>
      </div>
      </>
    );
  }

  return (
    <>
      {isLoading && <Loading />}
      <div className="min-h-screen" style={{ backgroundColor: '#0a0a0a' }}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h1 className="text-3xl font-bold text-white mb-8">طلباتي من Alpha Store</h1>

        {loading ? (
          <div className="text-center py-16">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-red-600"></div>
            <p className="text-gray-400 mt-4">جاري التحميل...</p>
          </div>
        ) : orders.length > 0 ? (
          <div className="space-y-6">
            {orders.map((order) => (
              <div key={order._id} className="card p-6">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h3 className="text-lg font-semibold text-white">طلب #{order._id.slice(-6)}</h3>
                    <p className="text-sm text-gray-400">التاريخ: {new Date(order.createdAt).toLocaleDateString('ar-SA')}</p>
                  </div>
                  <span className={`px-3 py-1 text-sm rounded-full ${
                    order.status === 'pending' ? 'bg-yellow-600 text-white' :
                    order.status === 'completed' ? 'bg-green-600 text-white' :
                    'bg-red-600 text-white'
                  }`}>
                    {order.status === 'pending' ? 'قيد الانتظار' :
                     order.status === 'completed' ? 'مكتمل' : 'ملغي'}
                  </span>
                </div>

                <div className="space-y-4">
                  {order.games.map((item, index) => (
                    <div key={index} className="border-b border-gray-700 pb-4 last:border-b-0">
                      <div className="flex justify-between items-start">
                        <div className="flex-1">
                          <h4 className="font-medium text-white mb-2">{item.game.title}</h4>
                          <div className="text-sm text-gray-400 space-x-4">
                            <span>المنصة: {item.game.platform}</span>
                            <span>السعر: ${item.price}</span>
                          </div>
                        </div>
                        <div className="text-lg font-semibold text-red-500">
                          ${item.price}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="border-t border-gray-700 pt-4">
                  <div className="flex justify-between items-center">
                    <span className="text-lg font-semibold text-white">المجموع:</span>
                    <span className="text-2xl font-bold text-red-500">${order.totalAmount}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-16">
            <div className="w-24 h-24 bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="h-12 w-12 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M8 11V7a4 4 0 00-8 0v4M4 11h16M4 11l4 4M20 11l-4 4" />
              </svg>
            </div>
            <h3 className="text-lg font-medium text-white mb-2">لا توجد طلبات</h3>
            <p className="text-gray-400 mb-6">لم تقم بشراء أي مفاتيح حتى الآن</p>
            <Link
              to="/"
              className="btn-primary inline-block"
            >
              تصفح المفاتيح
            </Link>
          </div>
        )}
      </div>
    </div>
    </>
  );
};

export default Cart;
